interface IIterator<T> {
  hasNext(): boolean;
  next(): T;
}

interface IterableCollection<T> {
  createIterator(): IIterator<T>;
}

class RangeIterator implements IIterator<number> {
  private current: number;

  constructor(
    start: number,
    private readonly end: number,
    private readonly step: number
  ) {
    this.current = start;
  }

  hasNext(): boolean {
    return this.current <= this.end;
  }

  next(): number {
    const value = this.current;
    this.current += this.step;
    return value;
  }
}

class NumberRange implements IterableCollection<number> {
  constructor(
    private readonly start: number,
    private readonly end: number,
    private readonly step: number = 1
  ) {}

  createIterator(): IIterator<number> {
    return new RangeIterator(this.start, this.end, this.step);
  }
}

// Usage
const range = new NumberRange(1, 10, 2);
const iterator = range.createIterator();

while (iterator.hasNext()) {
  console.log(iterator.next()); // 1, 3, 5, 7, 9
}

