import java.util.Iterator;
import java.util.NoSuchElementException;

class RangeIterator implements Iterator<Integer> {
    private int current;
    private final int end, step;

    RangeIterator(int start, int end, int step) {
        this.current = start; this.end = end; this.step = step;
    }

    public boolean hasNext() { return current <= end; }

    public Integer next() {
        if (!hasNext()) throw new NoSuchElementException();
        int value = current;
        current += step;
        return value;
    }
}

class NumberRange implements Iterable<Integer> {
    private final int start, end, step;

    NumberRange(int start, int end, int step) {
        this.start = start; this.end = end; this.step = step;
    }

    public Iterator<Integer> iterator() {
        return new RangeIterator(start, end, step);
    }
}

// Usage — works with Java's enhanced for-loop and streams
NumberRange range = new NumberRange(1, 10, 2);

for (int n : range) {
    System.out.print(n + " "); // 1 3 5 7 9
}

System.out.println(range.iterator().next()); // 1

