using System.Collections;
using System.Collections.Generic;

class NumberRange : IEnumerable<int>
{
    private readonly int _start, _end, _step;

    public NumberRange(int start, int end, int step = 1)
    { _start = start; _end = end; _step = step; }

    // yield return turns this method into a lazy iterator
    public IEnumerator<int> GetEnumerator()
    {
        for (int i = _start; i <= _end; i += _step)
            yield return i;
    }

    IEnumerator IEnumerable.GetEnumerator() => GetEnumerator();
}

// Usage — works with foreach and LINQ automatically
var range = new NumberRange(1, 10, 2);

foreach (int n in range)
    Console.Write(n + " "); // 1 3 5 7 9

Console.WriteLine();
Console.WriteLine(range.Max());                    // 9
Console.WriteLine(string.Join(", ", range));       // 1, 3, 5, 7, 9

