from __future__ import annotations
from collections.abc import Iterator, Iterable


class RangeIterator(Iterator[int]):
    def __init__(self, start: int, end: int, step: int) -> None:
        self._current = start
        self._end = end
        self._step = step

    def __next__(self) -> int:
        if self._current > self._end:
            raise StopIteration
        value = self._current
        self._current += self._step
        return value

    def __iter__(self) -> Iterator[int]:
        return self


class NumberRange(Iterable[int]):
    def __init__(self, start: int, end: int, step: int = 1) -> None:
        self.start = start
        self.end = end
        self.step = step

    def __iter__(self) -> Iterator[int]:
        return RangeIterator(self.start, self.end, self.step)


# Usage — works with all Python iteration constructs
range_ = NumberRange(1, 10, 2)

for n in range_:
    print(n, end=' ')   # 1 3 5 7 9

print(list(range_))     # [1, 3, 5, 7, 9]
print(max(range_))      # 9
